// User requests multiple items
const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "What are stock prices for AAPL, GOOGL, and MSFT?" }],
  tools: [getStockPriceTool]
});

// Claude returns multiple tool_use blocks
const toolUseBlocks = response.content.filter(c => c.type === "tool_use");
console.log(toolUseBlocks.length); // 3

// Store IDs before execution
const toolIds = toolUseBlocks.map(block => block.id);

// Execute in parallel
const results = await Promise.all(
  toolUseBlocks.map(block => {
    const { name, input } = block;
    return executeTool(name, input); // Returns result
  })
);

// Map results back to tool_use_ids
const toolResultBlocks = toolUseBlocks.map((block, i) => ({
  type: "tool_result",
  tool_use_id: block.id,  // Match original ID
  content: results[i].toString()
}));

// Send all results back in one message
const response2 = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    ...response.messages,
    { role: "user", content: toolResultBlocks } // One message with all results
  ],
  tools: [getStockPriceTool]
});

// Claude gives final answer
console.log(response2.content[0].text);
// "AAPL is $175.43, GOOGL is $142.67, MSFT is $378.91"

// Extract all tool_use blocks
const toolUseBlocks = response.content.filter(c => c.type === "tool_use");

// Process each one
toolUseBlocks.forEach(block => {
  const { name, input, id } = block;
  console.log(`Executing ${name} with input ${JSON.stringify(input)}, id: ${id}`);
});

// Execute all tools in parallel
const results = await Promise.all(
  toolUseBlocks.map(block => executeTool(block.name, block.input))
);

// Store IDs before execution
const toolIds = toolUseBlocks.map(block => block.id);

// Execute
const results = await Promise.all(
  toolUseBlocks.map(block => executeTool(block.name, block.input))
);

// Map with correct IDs
const toolResultBlocks = toolUseBlocks.map((block, i) => ({
  type: "tool_result",
  tool_use_id: block.id,  // Must match original
  content: results[i].toString()
}));

// ✅ Good: One message with all results
await client.messages.create({
  messages: [
    ...response.messages,
    { role: "user", content: toolResultBlocks } // All results together
  ]
});

// ❌ Bad: Multiple messages (sequential)
toolResultBlocks.forEach(result => {
  await client.messages.create({
    messages: [...response.messages, { role: "user", content: result }]
  });
});

// Basic prompting: ~100% parallel success rate
const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  system: "When you need multiple pieces of information, call all tools in parallel.",
  messages: [{ role: "user", content: "Get stock prices for AAPL, GOOGL, MSFT" }],
  tools: [getStockPriceTool]
});

// Instead of sequential calls, create a batch tool
const batchStockPricesTool = {
  name: "batch_stock_prices",
  description: "Get stock prices for multiple symbols in one call. Use when you need multiple prices.",
  input_schema: {
    type: "object",
    properties: {
      symbols: {
        type: "array",
        description: "List of stock symbols",
        items: { type: "string" }
      }
    },
    required: ["symbols"]
  }
};

// Claude calls ONE tool instead of 3
const response = await client.messages.create({
  messages: [{ role: "user", content: "Get stock prices for AAPL, GOOGL, MSFT" }],
  tools: [batchStockPricesTool]
});

// Your code executes once, returns all prices
const result = batchStockPrices(["AAPL", "GOOGL", "MSFT"]);
// [{ symbol: "AAPL", price: 175.43 }, { symbol: "GOOGL", price: 142.67 }, ...]
